on conflict (destination_key) do update set
  label = excluded.label,
  airfare = excluded.airfare,
  fuel_surcharge = excluded.fuel_surcharge,
  hotel_per_room = excluded.hotel_per_room,
  meal_per_person = excluded.meal_per_person,
  vehicle_large = excluded.vehicle_large,
  vehicle_small = excluded.vehicle_small,
  guide_fee = excluded.guide_fee,
  sightseeing_fee = excluded.sightseeing_fee,
  margin_per_traveler = excluded.margin_per_traveler;
